    private <T> T getCachedData(String cacheName, String key, Function<String, T> dbQuery) {
        // 尝试从 Caffeine 缓存获取
        Cache caffeineCache = caffeineCacheManager.getCache(cacheName);
        T value = caffeineCache.getIfPresent(key, T.class);

        if (value == null) {
            // 尝试从 Redis 缓存获取
